file_changes.replace:
.ds-sc-domains{grid-template-columns:repeat(3,1fr)}
.ds-thesis-hero{--ds-thesis-pulse-rgb:74,111,165;margin:1.6rem 0 1.4rem;padding:0;border:none}
@media(prefers-color-scheme:dark){.ds-thesis-hero{--ds-thesis-pulse-rgb:143,175,212}}
.ds-thesis-hero .ds-thesis-statement{font-family:var(--serif);font-size:clamp(1.85rem,3.6vw,2.65rem);line-height:1.18;font-weight:600;letter-spacing:-0.012em;color:var(--heading);margin:0 0 0.85rem;text-wrap:balance;max-width:32ch}
.ds-thesis-hero .ds-thesis-meta{margin:0 0 1rem}
.ds-thesis-hero .ds-thesis-badge{display:inline-flex;align-items:center;gap:.5rem;padding:.32rem .72rem;border:1px solid var(--accent);border-radius:999px;background:transparent;color:var(--accent);text-decoration:none;font-family:var(--sans);font-size:.82rem;font-weight:600;letter-spacing:0.02em;transition:background .15s,color .15s}
.ds-thesis-hero .ds-thesis-badge:hover{background:var(--accent);color:#fff;text-decoration:none}
.ds-thesis-hero .ds-thesis-badge:focus-visible{outline:2px solid var(--accent);outline-offset:2px}
.ds-thesis-hero .ds-thesis-badge-dot{display:inline-block;width:.55rem;height:.55rem;border-radius:50%;background:var(--accent);box-shadow:0 0 0 0 rgba(var(--ds-thesis-pulse-rgb),.55);animation:ds-thesis-badge-pulse 2.4s ease-out infinite}
.ds-thesis-hero .ds-thesis-badge:hover .ds-thesis-badge-dot{background:#fff;box-shadow:0 0 0 0 rgba(255,255,255,.6)}
.ds-thesis-hero .ds-thesis-badge-pre{text-transform:uppercase;font-size:.72rem;letter-spacing:0.08em;opacity:.85}
.ds-thesis-hero .ds-thesis-badge-date{font-weight:700}
@keyframes ds-thesis-badge-pulse{0%{box-shadow:0 0 0 0 rgba(var(--ds-thesis-pulse-rgb),.45)}70%{box-shadow:0 0 0 .55rem rgba(var(--ds-thesis-pulse-rgb),0)}100%{box-shadow:0 0 0 0 rgba(var(--ds-thesis-pulse-rgb),0)}}
@media(prefers-reduced-motion:reduce){.ds-thesis-hero .ds-thesis-badge-dot{animation:none}}
.ds-thesis-hero .ds-thesis-figures{list-style:none;margin:0;padding:.85rem 0 0;border-top:1px solid var(--rule);display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:1.1rem}
.ds-thesis-hero .ds-tf-item{display:flex;flex-direction:column;align-items:flex-start;gap:.18rem;font-family:var(--sans);min-width:0}
.ds-thesis-hero .ds-tf-number{font-family:var(--serif);font-size:1.55rem;font-weight:700;color:var(--heading);line-height:1.1;font-variant-numeric:tabular-nums}
.ds-thesis-hero .ds-tf-textnum{font-size:1.05rem;font-weight:700;color:var(--accent);letter-spacing:0.02em;text-transform:none}
.ds-thesis-hero .ds-tf-accent .ds-tf-number{color:var(--accent)}
.ds-thesis-hero .ds-tf-label{font-size:.78rem;text-transform:uppercase;letter-spacing:0.07em;color:var(--ink-3);font-weight:600;line-height:1.25}
.ds-thesis-hero .ds-tf-link{font-size:.78rem;color:var(--link);font-weight:500;margin-top:.1rem;text-decoration:underline}
.ds-thesis-hero .ds-tf-link:hover{text-decoration:none}
@media(max-width:760px){.ds-thesis-hero .ds-thesis-figures{grid-template-columns:repeat(2,minmax(0,1fr));gap:.9rem}.ds-thesis-hero .ds-tf-number{font-size:1.35rem}}
@media(max-width:420px){.ds-thesis-hero .ds-thesis-figures{grid-template-columns:1fr}}
.ds-verdict-bars{margin:1.5rem 0 2rem;padding:0;border:none}
